# Creating a Login Page in a React SPA

Building a login page in your React Single Page Application involves several steps. Here's a comprehensive guide:

## Basic Login Form Component

```jsx
import React, { useState } from 'react';
import './Login.css'; // Create this for styling

function Login({ onLogin }) {
  const [credentials, setCredentials] = useState({
    email: '',
    password: '',
  });
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setCredentials({ ...credentials, [name]: value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');

    try {
      // Replace with your actual API call
      const response = await fetch('https://your-api-url/login', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(credentials),
      });

      if (!response.ok) {
        throw new Error('Login failed');
      }

      const data = await response.json();
      // Store token in localStorage or sessionStorage
      localStorage.setItem('token', data.token);

      // Call the onLogin function passed from parent component
      onLogin(data.user);
    } catch (err) {
      setError('Invalid email or password');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="login-container">
      <h2>Login to Your Account</h2>
      <form onSubmit={handleSubmit} className="login-form">
        {error && <div className="error-message">{error}</div>}

        <div className="form-group">
          <label htmlFor="email">Email</label>
          <input
            type="email"
            id="email"
            name="email"
            value={credentials.email}
            onChange={handleChange}
            required
          />
        </div>

        <div className="form-group">
          <label htmlFor="password">Password</label>
          <input
            type="password"
            id="password"
            name="password"
            value={credentials.password}
            onChange={handleChange}
            required
          />
        </div>

        <button 
          type="submit" 
          disabled={isLoading} 
          className="login-button"
        >
          {isLoading ? 'Logging in...' : 'Login'}
        </button>

        <div className="additional-options">
          <a href="/forgot-password">Forgot password?</a>
          <a href="/register">Create an account</a>
        </div>
      </form>
    </div>
  );
}

export default Login;
```

## Authentication Context (for state management)

For better state management across your app, create an Auth Context:

```jsx
// AuthContext.js
import React, { createContext, useState, useContext, useEffect } from 'react';

const AuthContext = createContext(null);

export const AuthProvider = ({ children }) => {
  const [currentUser, setCurrentUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Check if user is already logged in (e.g., via token)
    const token = localStorage.getItem('token');
    if (token) {
      // You might want to validate the token with your backend here
      fetchUserData(token);
    } else {
      setLoading(false);
    }
  }, []);

  const fetchUserData = async (token) => {
    try {
      const response = await fetch('https://your-api-url/me', {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });

      if (response.ok) {
        const userData = await response.json();
        setCurrentUser(userData);
      } else {
        // Token invalid, clear it
        localStorage.removeItem('token');
      }
    } catch (error) {
      console.error('Failed to fetch user data', error);
    } finally {
      setLoading(false);
    }
  };

  const login = (userData) => {
    setCurrentUser(userData);
  };

  const logout = () => {
    localStorage.removeItem('token');
    setCurrentUser(null);
  };

  return (
    <AuthContext.Provider value={{ currentUser, login, logout, loading }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => useContext(AuthContext);
```

## Protected Route Component

Create a component to protect routes that require authentication:

```jsx
// ProtectedRoute.js
import React from 'react';
import { Navigate } from 'react-router-dom';
import { useAuth } from './AuthContext';

function ProtectedRoute({ children }) {
  const { currentUser, loading } = useAuth();

  if (loading) {
    return <div>Loading...</div>;
  }

  if (!currentUser) {
    return <Navigate to="/login" />;
  }

  return children;
}

export default ProtectedRoute;
```

## Setting Up Routes

In your main app file or router configuration:

```jsx
// App.js or Router.js
import React from 'react';
import { BrowserRouter, Routes, Route } from 'react-router-dom';
import { AuthProvider } from './AuthContext';
import Login from './Login';
import Dashboard from './Dashboard';
import ProtectedRoute from './ProtectedRoute';
import Register from './Register';
import ForgotPassword from './ForgotPassword';

function App() {
  return (
    <AuthProvider>
      <BrowserRouter>
        <Routes>
          <Route path="/login" element={<Login />} />
          <Route path="/register" element={<Register />} />
          <Route path="/forgot-password" element={<ForgotPassword />} />
          <Route path="/dashboard" element={
            <ProtectedRoute>
              <Dashboard />
            </ProtectedRoute>
          } />
          <Route path="/" element={<Navigate to="/dashboard" />} />
        </Routes>
      </BrowserRouter>
    </AuthProvider>
  );
}

export default App;
```

## Adding Basic Styling

```css
/* Login.css */
.login-container {
  max-width: 400px;
  margin: 50px auto;
  padding: 20px;
  border-radius: 8px;
  box-shadow: 0 0 10px rgba(0, 0, 0, 0.1);
}

.login-form {
  display: flex;
  flex-direction: column;
  gap: 15px;
}

.form-group {
  display: flex;
  flex-direction: column;
  gap: 5px;
}

.form-group label {
  font-weight: 500;
}

.form-group input {
  padding: 10px;
  border: 1px solid #ddd;
  border-radius: 4px;
  font-size: 16px;
}

.error-message {
  color: #e53935;
  background-color: #ffebee;
  padding: 10px;
  border-radius: 4px;
  margin-bottom: 10px;
}

.login-button {
  padding: 12px;
  background-color: #4caf50;
  color: white;
  border: none;
  border-radius: 4px;
  cursor: pointer;
  font-size: 16px;
  font-weight: 500;
}

.login-button:disabled {
  background-color: #9e9e9e;
  cursor: not-allowed;
}

.additional-options {
  display: flex;
  justify-content: space-between;
  margin-top: 10px;
}

.additional-options a {
  color: #2196f3;
  text-decoration: none;
}

.additional-options a:hover {
  text-decoration: underline;
}
```

## Best Practices

1. **Security**: 
   - Never store sensitive information like passwords in local storage
   - Use HTTPS for all API requests
   - Implement proper token validation on the backend

2. **User Experience**:
   - Add proper form validation
   - Show loading states
   - Provide clear error messages

3. **Accessibility**:
   - Ensure your form is accessible (proper labels, keyboard navigation)
   - Support screen readers with appropriate ARIA attributes

4. **Performance**:
   - Lazy load authentication-related components
   - Consider using React.memo for components that don't need frequent re-renders

This implementation gives you a solid foundation for a login system in your React SPA. You can extend it with additional features like remember me functionality, multi-factor authentication, or social login options.
